/**
 * @param {number[]} nums1
 * @param {number[]} nums0
 * @return {number}
 */
function solve(nums1, nums0) {
    const MOD = 10**9 + 7;

    // Modular exponentiation: (base^exp) % mod
    const power = (base, exp) => {
        let res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 === 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp = Math.floor(exp / 2);
        }
        return res;
    };

    // 1. Prepare fragments data
    const fragments = [];
    const N = nums1.length;
    for (let i = 0; i < N; i++) {
        fragments.push({ n1: nums1[i], n0: nums0[i] });
    }

    // 2. Define custom comparator for sorting
    // A precedes B if AB > BA lexicographically.
    // This translates to: prefer more leading ones (n1), and if n1 is equal, prefer fewer trailing zeros (n0).
    fragments.sort((A, B) => {
        // Rule 1: Compare n1
        if (A.n1 !== B.n1) {
            // If A has more ones, A should come first (return -1)
            return B.n1 - A.n1; // Sort descending by n1
        }

        // Rule 2: n1 are equal, compare n0
        // If A has fewer zeros, A should come first (return -1)
        return A.n0 - B.n0; // Sort ascending by n0
    });

    // 3. Calculate the total value modulo MOD
    let totalValue = 0;

    for (const frag of fragments) {
        const n1 = frag.n1;
        const n0 = frag.n0;

        // Fragment length L = n1 + n0
        const L = n1 + n0;

        // Step 1: Shift existing total value left by L bits
        // totalValue = (totalValue * 2^L) % MOD
        const powerL = power(2, L);
        totalValue = (totalValue * powerL) % MOD;

        // Step 2: Calculate the value of the current fragment S_i = 1^n1 0^n0
        // Value(S_i) = 2^n0 * (2^n1 - 1) mod M

        // Calculate 2^n1 - 1 mod M
        const powerN1 = power(2, n1);
        // Ensure positive result for subtraction
        const term2 = (powerN1 - 1 + MOD) % MOD; 

        // Calculate 2^n0 mod M
        const powerN0 = power(2, n0);

        // V_S = (2^n0 * (2^n1 - 1)) mod M
        const V_S = (powerN0 * term2) % MOD;

        // Step 3: Add V_S to the total value
        totalValue = (totalValue + V_S) % MOD;
    }

    return totalValue;
}

