package main

import (
	"sort"
)

// Define the modulus
const MOD int64 = 1e9 + 7

// Fragment structure
type Fragment struct {
	N1 int64
	N0 int64
}

// Modular exponentiation: (base^exp) % mod
func power(base, exp int64) int64 {
	res := int64(1)
	base %= MOD
	for exp > 0 {
		if exp%2 == 1 {
			res = (res * base) % MOD
		}
		base = (base * base) % MOD
		exp /= 2
	}
	return res
}

// Custom sorter implementation
type ByFragment []Fragment

func (a ByFragment) Len() int { return len(a) }
func (a ByFragment) Swap(i, j int) { a[i], a[j] = a[j], a[i] }
func (a ByFragment) Less(i, j int) bool {
	// We want A before B if AB > BA.
	// This is equivalent to: prefer more leading ones (N1 descending), 
	// then prefer fewer trailing zeros (N0 ascending).

	// Rule 1: Compare N1 (Descending order, so a[i] is "less" if it should come later)
	if a[i].N1 != a[j].N1 {
		return a[i].N1 > a[j].N1 // True if a[i].N1 is GREATER than a[j].N1
	}

	// Rule 2: N1 are equal, compare N0 (Ascending order)
	return a[i].N0 < a[j].N0 // True if a[i].N0 is LESS than a[j].N0
}

func solve(nums1 []int64, nums0 []int64) int64 {
	// 1. Prepare fragments data
	fragments := make([]Fragment, len(nums1))
	for i := 0; i < len(nums1); i++ {
		fragments[i] = Fragment{N1: nums1[i], N0: nums0[i]}
	}

	// 2. Sort fragments using the custom comparator
	sort.Sort(ByFragment(fragments))

	// 3. Calculate the total value modulo MOD
	var totalValue int64 = 0

	for _, frag := range fragments {
		n1 := frag.N1
		n0 := frag.N0

		// Fragment length L = n1 + n0
		L := n1 + n0

		// Step 1: Shift existing total value left by L bits
		// totalValue = (totalValue * 2^L) % MOD
		powerL := power(2, L)
		totalValue = (totalValue * powerL) % MOD

		// Step 2: Calculate the value of the current fragment S_i = 1^n1 0^n0
		// V_S = 2^n0 * (2^n1 - 1) mod M

		// Calculate 2^n1 - 1 mod M
		powerN1 := power(2, n1)
		// Ensure positive result for subtraction: (A - 1 + M) % M
		term2 := (powerN1 - 1 + MOD) % MOD 

		// Calculate 2^n0 mod M
		powerN0 := power(2, n0)

		// V_S = (2^n0 * term2) mod M
		VS := (powerN0 * term2) % MOD

		// Step 3: Add V_S to the total value
		totalValue = (totalValue + VS) % MOD
