import (
	"sort"
)

const MOD int64 = 1e9 + 7

// Fragment stores the counts of '1's and '0's for a fragment.
type Fragment struct {
	n1 int64
	n0 int64
}

// power calculates (base^exp) % MOD using modular exponentiation.
func power(base, exp int64) int64 {
	res := int64(1)
	base %= MOD
	for exp > 0 {
		if exp%2 == 1 {
			res = (res * base) % MOD
		}
		base = (base * base) % MOD
		exp /= 2
	}
	return res
}

func solve(nums1 []int64, nums0 []int64) int64 {
	N := len(nums1)
	fragments := make([]Fragment, N)

	// 1. Prepare fragments data
	for i := 0; i < N; i++ {
		fragments[i] = Fragment{n1: nums1[i], n0: nums0[i]}
	}

	// 2. Define custom comparator for sorting
	// We prefer A before B if AB > BA lexicographically.
	// Rule: Sort descending by n1. If n1 are equal, sort ascending by n0.
	sort.Slice(fragments, func(i, j int) bool {
		A := fragments[i]
		B := fragments[j]

		// Compare n1 (descending order: A comes before B if A.n1 > B.n1)
		if A.n1 != B.n1 {
			return A.n1 > B.n1
		}

		// n1 are equal, compare n0 (ascending order: A comes before B if A.n0 < B.n0)
		return A.n0 < B.n0
	})

	// 3. Calculate the total value modulo MOD
	totalValue := int64(0)

	for _, frag := range fragments {
		n1 := frag.n1
		n0 := frag.n0

		// Fragment length L = n1 + n0
		L := n1 + n0

		// Step 1: Shift existing total value left by L bits
		// totalValue = (totalValue * 2^L) % MOD
		powerL := power(2, L)
		totalValue = (totalValue * powerL) % MOD

		// Step 2: Calculate the value of the current fragment S_i = 1^n1 0^n0
		// Value(S_i) = (2^n1 - 1) * 2^n0 mod M

		// Calculate 2^n1 - 1 mod M
		powerN1 := power(2, n1)
		// Ensure positive result for subtraction: (A - B) % M = (A - B + M) % M
		term2 := (powerN1 - 1 + MOD) % MOD

		// Calculate 2^n0 mod M
		powerN0 := power(2, n0)

		// V_S = (term2 * powerN0) mod M
		V_S := (term2 * powerN0) % MOD

		// Step 3: Add V_S to the total value
		totalValue = (totalValue + V_S) % MOD
	}

	return totalValue
}

